     2→ * AI Provider Fallback Service — Comprehensive Multi-Provider System
     3→ *
     4→ * Provides automatic failover between AI providers per modality.
     5→ * When a provider fails (401, 402, 429, timeout), automatically
     6→ * switches to the next provider in the chain. No manual intervention.
     7→ *
     8→ * Modalities: LLM, TTS, ASR, Vision, Embedding, Reranking, Safety
     9→ * Providers: Polsia/Anthropic, Polsia/OpenAI, NVIDIA NIM (20+ models)
    10→ *
    11→ * Per-module routing: Different HireLoop modules can request specialized
    12→ * chains optimized for their use case (e.g., reasoning models for assessments,
    13→ * cheap models for bulk onboarding, multimodal for resume parsing).
    14→ */
    15→
    16→const OpenAI = require('openai');
    17→const Anthropic = require('@anthropic-ai/sdk');
    18→const fetch = require('node-fetch');
    19→const FormData = require('form-data');
    20→const tokenBudget = require('./token-budget');
    21→const pool = require('./db');
    22→
    23→let activityLogger;
    24→try {
    25→  activityLogger = require('./activity-logger');
    26→} catch (e) {
    27→  activityLogger = { logAICall: () => {}, logFailover: () => {}, logBudgetExhausted: () => {} };
    28→}
    29→
    30→let aiCallLogger;
    31→try {
    32→  aiCallLogger = require('./ai-call-logger');
    33→} catch (e) {
    34→  aiCallLogger = { logCall: () => {}, shouldThrottle: () => false };
    35→}
    36→
    37→let selfHostedAudio;
    38→try {
    39→  selfHostedAudio = require('./self-hosted-audio');
    40→} catch (e) {
    41→  selfHostedAudio = null;
    42→}
    43→
    44→// Circuit breaker: skip providers that failed recently
    45→const CIRCUIT_BREAK_MS = 5 * 60 * 1000; // 5 minutes
    46→// Extended circuit break for geo-blocked providers (30 min — these won't magically start working)
    47→const GEO_BLOCK_CIRCUIT_MS = 30 * 60 * 1000;
    48→
    49→// HTTP status codes that indicate provider-level issues (retryable)
    50→// 400 included: Polsia proxy wraps upstream provider errors (e.g., Gemini "User location
    51→// not supported") as 400 with code: 'proxy_error'. Must not abort the fallback chain.
    52→// 404 included: NIM audio endpoints return 404 (not available on cloud API),
    53→// must not abort the entire fallback chain — try the next provider instead.
    54→const RETRYABLE_STATUS = new Set([400, 401, 402, 404, 429, 500, 502, 503, 504]);
    55→
    56→// ─── TIMEOUT CASCADE FIX (Feb 15, 2026) ──────────────────────────
    57→// BUG: Sequential fallback through 12 LLM providers × 15s timeout = 180s worst case.
    58→// FIX: (1) Cap total wall-clock time per modality, (2) Race top N providers in parallel.
    59→
    60→// Total cascade timeout — absolute max wall-clock time for the entire execute() call
    61→const TOTAL_CASCADE_TIMEOUT = {
    62→  llm: 16000,       // 16s max (was 30s → too long with 4 concurrent Quick Practice calls)
