   700→    return false;
   701→  }
   702→
   703→  // Check if a provider key is an OpenAI provider (not Anthropic, not NIM)
   704→  _isOpenAIProvider(providerKey) {
   705→    return providerKey === 'openai' || providerKey.startsWith('openai_');
   706→  }
   707→
   708→  // Get available providers for a modality (skipping unavailable + circuit-broken + budget-exhausted OpenAI)
   709→  getAvailableChain(modality, variant = 'default') {
   710→    const budgetExhausted = tokenBudget.isOpenAIBudgetExhausted();
   711→    // TTS and ASR are exempt from budget exhaustion — they use minimal tokens
   712→    // (~50-100 per TTS call, ~30-50 per ASR call) and have NO working NIM fallbacks
   713→    // (NVIDIA cloud API doesn't host audio models). Blocking them kills interviews.
   714→    const budgetExemptModalities = new Set(['tts', 'asr']);
   715→    const skipOpenAI = budgetExhausted && !budgetExemptModalities.has(modality);
   716→
   717→    return this.getChain(modality, variant).filter(key => {
   718→      if (!this.isProviderAvailable(key)) return false;
   719→      if (this.isCircuitOpen(key, modality)) return false;
   720→      // Skip OpenAI providers when daily token budget is exhausted (except TTS/ASR)
   721→      if (skipOpenAI && this._isOpenAIProvider(key)) return false;
   722→      return true;
   723→    });
   724→  }
   725→
   726→  // ─── Core Execution with Fallback ────────────────────────────
   727→
   728→  /**
   729→   * Execute an AI call with automatic fallback.
   730→   *
   731→   * FEB 15, 2026 FIX: Parallel racing + total cascade timeout.
   732→   * Before: Sequential through 12 providers × 15s = 180s worst case.
   733→   * After: Race top 3, cap at 30s total. First success wins.
   734→   *
   735→   * @param {string} modality - 'llm', 'vision', 'tts', 'asr', 'embedding', 'reranking', 'safety'
   736→   * @param {Function} executeFn - async (providerKey) => result
   737→   * @param {string} variant - Chain variant (default, quality, efficient, reasoning)
   738→   * @returns {*} Result from the first successful provider
   739→   */
   740→  async execute(modality, executeFn, variant = 'default', callMeta = {}) {
   741→    const callStart = Date.now();
   742→    const chain = this.getAvailableChain(modality, variant);
   743→    const triedProviders = [];
   744→
   745→    if (chain.length === 0) {
   746→      const allChain = this.getChain(modality, variant);
   747→      const reasons = allChain.map(k => {
   748→        if (!this.isProviderAvailable(k)) return `${k}: not configured`;
   749→        if (this.isCircuitOpen(k, modality)) return `${k}: circuit open`;
   750→        return `${k}: unknown`;
   751→      });
   752→      const err = new Error(`No available providers for ${modality}. ${reasons.join(', ')}`);
   753→      err.allProvidersFailed = true;
   754→      err.triedProviders = [];
   755→      err.totalElapsedMs = Date.now() - callStart;
   756→      aiCallLogger.logCall({
   757→        module: callMeta.module || 'unknown',
   758→        feature: callMeta.feature || '',
   759→        modality,
   760→        provider: 'none',
   761→        model: '',
   762→        latencyMs: Date.now() - callStart,
   763→        success: false,
   764→        errorMessage: err.message,
   765→        fallbackChain: allChain,
   766→        userId: callMeta.userId || null,
   767→      });
   768→      throw err;
   769→    }
   770→
   771→    // Per-provider timeout: 8s for TTS/ASR, 10s for LLM, 30s for vision (multi-image), 10s default
