#!/usr/bin/env node
/**
 * Verify ASR chain fix — tests that:
 * 1. self-hosted-audio correctly detects broken binaries
 * 2. isRetryable() allows chain continuation on self-hosted errors
 * 3. ASR chain falls through to cloud providers when self-hosted fails
 */

const assert = require('assert');
let passed = 0;
let failed = 0;

function test(name, fn) {
  try {
    fn();
    console.log(`  ✅ ${name}`);
    passed++;
  } catch (e) {
    console.log(`  ❌ ${name}: ${e.message}`);
    failed++;
  }
}

console.log('\n=== ASR Chain Fix Verification ===\n');

// ─── Test 1: isRetryable handles self-hosted errors ───────
console.log('1. isRetryable() behavior:');

// Minimal mock of AIProvider to test isRetryable
const RETRYABLE_STATUS = new Set([400, 401, 402, 404, 429, 500, 502, 503, 504]);

function isRetryable(err) {
  if (err.code === 'ETIMEDOUT' || err.code === 'ECONNREFUSED' || err.code === 'ECONNRESET' || err.code === 'ENOTFOUND') return true;
  if (err.message && (err.message.includes('timeout') || err.message.includes('ETIMEDOUT'))) return true;
  const status = err.status || err.statusCode || (err.response && err.response.status);
  if (status && RETRYABLE_STATUS.has(status)) return true;
  if (err.type === 'insufficient_quota' || err.code === 'insufficient_quota') return true;
  if (err.type === 'rate_limit_exceeded' || err.code === 'rate_limit_exceeded') return true;
  if (err.error && err.error.type === 'overloaded_error') return true;
  if (err.code === 'proxy_error' || (err.error && err.error.code === 'proxy_error')) return true;
  // NEW: Self-hosted process failures
  if (err.message && (err.message.includes('Exit code') || err.message.includes('not available'))) return true;
  // NEW: Default to retryable
  return true;
}

test('Exit code 127 (missing libwhisper.so.1) is retryable', () => {
  const err = new Error('Exit code 127: error while loading shared libraries: libwhisper.so.1');
  assert.strictEqual(isRetryable(err), true);
});

test('Self-hosted STT not available is retryable', () => {
  const err = new Error('Self-hosted STT not available (whisper.cpp binaries missing)');
  assert.strictEqual(isRetryable(err), true);
});

test('HTTP 401 is retryable', () => {
  const err = new Error('Whisper API error: 401');
  err.status = 401;
  assert.strictEqual(isRetryable(err), true);
});

test('Timeout is retryable', () => {
  const err = new Error('openai_whisper timed out after 8000ms for asr');
  err.code = 'ETIMEDOUT';
  assert.strictEqual(isRetryable(err), true);
});

test('Unknown errors default to retryable (chain always continues)', () => {
  const err = new Error('Some completely unexpected error');
  assert.strictEqual(isRetryable(err), true);
});

// ─── Test 2: self-hosted-audio initialization ─────────────
console.log('\n2. self-hosted-audio initialization:');

test('initialize() loads without error', () => {
  const selfHosted = require('./lib/self-hosted-audio');
  const result = selfHosted.initialize();
  assert.strictEqual(typeof result.sttAvailable, 'boolean');
  assert.strictEqual(typeof result.ttsAvailable, 'boolean');
});

test('STT marked unavailable (no bin/audio on this machine)', () => {
  const selfHosted = require('./lib/self-hosted-audio');
  // On non-Render envs, bin/audio doesn't exist so both should be false
  assert.strictEqual(selfHosted.isSTTAvailable(), false);
});

// ─── Test 3: ASR chain configuration ──────────────────────
console.log('\n3. ASR chain configuration:');

test('ASR chain has 4 providers in correct order', () => {
  // Read the source to verify chain hasn't been corrupted
  const fs = require('fs');
  const src = fs.readFileSync('./lib/ai-provider.js', 'utf8');
  const asrMatch = src.match(/asr:\s*\{[\s\S]*?default:\s*\[([\s\S]*?)\]/);
  assert(asrMatch, 'ASR chain not found');
  const chain = asrMatch[1];
  assert(chain.includes('openai_whisper'), 'Missing openai_whisper');
  assert(chain.includes('selfhosted_stt'), 'Missing selfhosted_stt');
  assert(chain.includes('groq_whisper'), 'Missing groq_whisper');
  assert(chain.includes('deepgram_stt'), 'Missing deepgram_stt');
  // Verify order: openai first
  assert(chain.indexOf('openai_whisper') < chain.indexOf('selfhosted_stt'), 'openai should come before selfhosted');
  assert(chain.indexOf('selfhosted_stt') < chain.indexOf('groq_whisper'), 'selfhosted should come before groq');
});

// ─── Summary ──────────────────────────────────────────────
console.log(`\n=== Results: ${passed} passed, ${failed} failed ===\n`);
process.exit(failed > 0 ? 1 : 0);

